function checkVelocity(ent: Entity): void {
  for (let i = 0; i < 3; i++) {
    if (isNaN(ent.velocity[i])) {
      throw new Error(`NaN velocity on entity ${ent.classname} component ${i}`);
    }
    if (Math.abs(ent.velocity[i]) > svMaxVelocity) {
      throw new RangeError(
        `Velocity ${ent.velocity[i]} exceeds max ${svMaxVelocity} on ${ent.classname}`
      );
    }
  }
}
